import {
  type AdditionalFieldValue,
  parseAdditionalFieldValue
} from "@better-auth-ui/core"
import { useAuth, useSession, useUpdateUser } from "@better-auth-ui/solid"
import { createSignal, For } from "solid-js"
import { toast } from "solid-sonner"
import { AdditionalField } from "@/components/auth/additional-field"
import { ChangeAvatar } from "@/components/auth/settings/account/change-avatar"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { cn } from "@/lib/utils"

export type UserProfileProps = {
  class?: string
}

export function UserProfile(props: UserProfileProps = {}) {
  const auth = useAuth()
  const session = useSession(auth.authClient)
  const [name, setName] = createSignal("")
  const { mutate: updateUser, isPending: updateUserPending } = useUpdateUser(
    auth.authClient,
    {
      onSuccess: () =>
        toast.success(auth.localization.settings.profileUpdatedSuccess)
    }
  )

  const profileFields = () =>
    auth.additionalFields?.filter((field) => field.profile !== false) ?? []

  const submitProfile = async (event: SubmitEvent) => {
    event.preventDefault()

    const formData = new FormData(event.currentTarget as HTMLFormElement)
    const name = String(formData.get("name") ?? "")
    const additionalFieldValues: Record<string, unknown> = {}

    for (const field of auth.additionalFields ?? []) {
      if (field.profile === false || field.readOnly) continue

      const value = parseAdditionalFieldValue(
        field,
        formData.get(field.name) as string | null
      )

      if (field.validate) {
        try {
          await field.validate(value)
        } catch (error) {
          toast.error(error instanceof Error ? error.message : String(error))
          return
        }
      }

      if (value !== undefined) {
        additionalFieldValues[field.name] = value
      }
    }

    updateUser({
      name,
      ...additionalFieldValues
    })
  }

  return (
    <div class={cn(props.class)}>
      <h2 class="mb-3 text-sm font-semibold">
        {auth.localization.settings.userProfile}
      </h2>
      <form aria-label="Profile" onSubmit={submitProfile}>
        <Card>
          <CardContent class="flex flex-col gap-6">
            <ChangeAvatar />

            <div class="grid gap-2">
              <Label for="settings-name">{auth.localization.auth.name}</Label>
              <Input
                autocomplete="name"
                disabled={updateUserPending}
                id="settings-name"
                name="name"
                onInput={(event) => setName(event.currentTarget.value)}
                placeholder={auth.localization.auth.name}
                required
                value={name() || (session.data?.user.name ?? "")}
              />
            </div>

            <For each={profileFields()}>
              {(field) => {
                const value = () =>
                  (session.data?.user as Record<string, unknown> | undefined)?.[
                    field.name
                  ]

                return (
                  <AdditionalField
                    field={{
                      ...field,
                      defaultValue: value() as AdditionalFieldValue | null
                    }}
                    isPending={updateUserPending || !session.data}
                    name={field.name}
                  />
                )
              }}
            </For>
          </CardContent>
          <CardFooter>
            <Button
              aria-label="Save changes"
              disabled={updateUserPending || !session.data}
              size="sm"
              type="submit"
            >
              {auth.localization.settings.saveChanges}
            </Button>
          </CardFooter>
        </Card>
      </form>
    </div>
  )
}

import { fileToBase64 } from "@better-auth-ui/core"
import { useAuth, useSession, useUpdateUser } from "@better-auth-ui/solid"
import { Trash2, Upload } from "lucide-solid"
import { createSignal } from "solid-js"
import { toast } from "solid-sonner"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger
} from "@/components/ui/dropdown-menu"
import { Label } from "@/components/ui/label"
import { resolveUserInitials, resolveUserLabel } from "../shared/helpers"

export type ChangeAvatarProps = {
  className?: string
}

export function ChangeAvatar(props: ChangeAvatarProps) {
  const auth = useAuth()
  const session = useSession(auth.authClient)
  const [isUploadingAvatar, setIsUploadingAvatar] = createSignal(false)
  const [isDeletingAvatar, setIsDeletingAvatar] = createSignal(false)
  let avatarFileInput: HTMLInputElement | undefined
  const updateUser = useUpdateUser(auth.authClient)
  const displayName = () =>
    resolveUserLabel(session.data?.user.name, session.data?.user.email)
  const isPending = () =>
    updateUser.isPending || isUploadingAvatar() || isDeletingAvatar()

  const handleAvatarFileChange = async (event: Event) => {
    const input = event.currentTarget as HTMLInputElement
    const file = input.files?.[0]

    if (!file) return

    input.value = ""
    setIsUploadingAvatar(true)

    try {
      const resized =
        (await auth.avatar.resize?.(
          file,
          auth.avatar.size,
          auth.avatar.extension
        )) || file
      const image =
        (await auth.avatar.upload?.(resized)) || (await fileToBase64(resized))

      updateUser.mutate(
        { image },
        {
          onSuccess: () =>
            toast.success(auth.localization.settings.avatarChangedSuccess)
        }
      )
    } catch (error) {
      if (error instanceof Error) {
        toast.error(error.message)
      }
    } finally {
      setIsUploadingAvatar(false)
    }
  }

  const deleteAvatar = () => {
    const currentImage = session.data?.user.image

    updateUser.mutate(
      { image: null },
      {
        onSuccess: async () => {
          if (currentImage) {
            setIsDeletingAvatar(true)
            try {
              await auth.avatar.delete?.(currentImage)
            } finally {
              setIsDeletingAvatar(false)
            }
          }

          toast.success(auth.localization.settings.avatarDeletedSuccess)
        }
      }
    )
  }

  return (
    <div class={props.className ?? "grid gap-2"}>
      <Label>{auth.localization.settings.avatar}</Label>
      <input
        accept="image/*"
        class="hidden"
        onChange={handleAvatarFileChange}
        ref={avatarFileInput}
        type="file"
      />
      <div class="flex items-center gap-4">
        <Button
          class="h-auto w-auto rounded-full p-0"
          disabled={isPending()}
          onClick={() => avatarFileInput?.click()}
          type="button"
          variant="ghost"
        >
          <Avatar class="size-18 rounded-full bg-muted text-muted-foreground">
            <AvatarImage
              alt={displayName()}
              sizes="lg"
              src={session.data?.user.image ?? undefined}
            />
            <AvatarFallback class="rounded-full bg-muted text-muted-foreground">
              {resolveUserInitials(
                session.data?.user.name,
                session.data?.user.email
              )}
            </AvatarFallback>
          </Avatar>
        </Button>

        <DropdownMenu>
          <DropdownMenuTrigger
            as={Button}
            class=""
            disabled={!session.data || isPending()}
            size="sm"
            variant="secondary"
          >
            {auth.localization.settings.changeAvatar}
          </DropdownMenuTrigger>
          <DropdownMenuContent class="min-w-fit">
            <DropdownMenuItem onSelect={() => avatarFileInput?.click()}>
              <Upload class="text-muted-foreground" />
              {auth.localization.settings.uploadAvatar}
            </DropdownMenuItem>
            <DropdownMenuItem
              disabled={!session.data?.user.image}
              onSelect={deleteAvatar}
              variant="destructive"
            >
              <Trash2 />
              {auth.localization.settings.deleteAvatar}
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </div>
  )
}

import {
  type AdditionalField as AdditionalFieldConfig,
  resolveInputType
} from "@better-auth-ui/core"
import { createSignal, For, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

export type AdditionalFieldProps = {
  field: AdditionalFieldConfig
  isPending?: boolean
  name: string
}

const valueToString = (value: AdditionalFieldConfig["defaultValue"]) =>
  value == null
    ? ""
    : value instanceof Date
      ? value.toISOString()
      : String(value)

/**
 * Canonical Solid renderer for additional auth fields.
 *
 * The Solid/Zaidan example does not yet ship all shadcn field primitives
 * (calendar, combobox, slider, switch). Unsupported advanced input types are
 * guarded by rendering semantic native controls instead of inventing UI-only
 * behavior.
 */
export function AdditionalField(props: AdditionalFieldProps) {
  const [copied, setCopied] = createSignal(false)
  let inputRef: HTMLInputElement | undefined
  const inputType = () => resolveInputType(props.field)
  const defaultValue = () => valueToString(props.field.defaultValue)
  const isDisabled = () => props.isPending || props.field.readOnly
  const nativeType = () => {
    switch (inputType()) {
      case "number":
      case "date":
      case "hidden":
        return inputType()
      case "datetime":
        return "datetime-local"
      default:
        return props.field.type === "number" ? "number" : "text"
    }
  }

  const copyValue = async () => {
    const value = inputRef?.value
    if (!value) return

    await navigator.clipboard.writeText(value)
    setCopied(true)
    window.setTimeout(() => setCopied(false), 1500)
  }

  if (props.field.render) {
    return <>{props.field.render(props)}</>
  }

  if (inputType() === "hidden") {
    return <input name={props.name} type="hidden" value={defaultValue()} />
  }

  if (inputType() === "textarea") {
    return (
      <div class="grid gap-2">
        <Label for={props.name}>{props.field.label}</Label>
        <textarea
          class="z-input min-h-24 w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm outline-none placeholder:text-muted-foreground disabled:pointer-events-none disabled:opacity-50"
          disabled={props.isPending}
          id={props.name}
          name={props.name}
          placeholder={props.field.placeholder}
          readonly={props.field.readOnly}
          required={props.field.required}
        >
          {defaultValue()}
        </textarea>
      </div>
    )
  }

  if (inputType() === "select" || inputType() === "combobox") {
    return (
      <div class="grid gap-2">
        <Label for={props.name}>{props.field.label}</Label>
        <select
          class="z-input w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm outline-none disabled:pointer-events-none disabled:opacity-50"
          disabled={isDisabled()}
          id={props.name}
          name={props.name}
          required={props.field.required}
          value={defaultValue()}
        >
          <Show when={props.field.placeholder}>
            <option disabled value="">
              {props.field.placeholder}
            </option>
          </Show>
          <For each={props.field.options ?? []}>
            {(option) => <option value={option.value}>{option.label}</option>}
          </For>
        </select>
      </div>
    )
  }

  if (inputType() === "switch" || inputType() === "checkbox") {
    return (
      <label class="flex items-center gap-3 text-sm">
        <input
          checked={
            props.field.defaultValue === true || defaultValue() === "true"
          }
          disabled={isDisabled()}
          name={props.name}
          required={props.field.required}
          type="checkbox"
        />
        {props.field.label}
      </label>
    )
  }

  return (
    <div class="grid gap-2">
      <Label for={props.name}>{props.field.label}</Label>
      <div class="flex items-center gap-2">
        <Show when={props.field.prefix}>
          <span class="text-muted-foreground text-sm">
            {props.field.prefix}
          </span>
        </Show>
        <Input
          disabled={props.isPending}
          id={props.name}
          max={props.field.max}
          min={props.field.min}
          name={props.name}
          placeholder={props.field.placeholder}
          readonly={props.field.readOnly}
          ref={inputRef}
          required={props.field.required}
          step={props.field.step}
          type={nativeType()}
          value={defaultValue()}
        />
        <Show when={props.field.copyable}>
          <Button
            disabled={props.isPending}
            onClick={copyValue}
            type="button"
            variant="outline"
          >
            {copied() ? "Copied" : "Copy"}
          </Button>
        </Show>
        <Show when={props.field.suffix}>
          <span class="text-muted-foreground text-sm">
            {props.field.suffix}
          </span>
        </Show>
      </div>
    </div>
  )
}

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
